    expected_pairs: config.expected_pairs,
    actual_pairs: $('PG: Check Experiment').first()?.json?.total_pairs || 0
  }
}];

const candidate = $json.candidate_json;
const vacancy = $json.vacancy_json;
const caseVacancyId = $json.case_vacancy_id;

const experimentData = $('PG: Check Experiment').first().json;
const judgePrompt = experimentData.judge_prompt_text;

return [{
  json: {
    case_vacancy_id: caseVacancyId,
    request_started_at: Date.now(),
    candidate: candidate,
    vacancy: vacancy,
    openai_body: {
      model: experimentData.model_judge || 'gpt-4.1-2025-04-14',
      temperature: Number(experimentData.temperature_judge ?? 0),
      messages: [
        {
          role: 'system',
          content: judgePrompt
        },
        {
          role: 'user',
          content: 'Кандидат:\n' + JSON.stringify(candidate, null, 2) + '\n\nВакансия:\n' + JSON.stringify(vacancy, null, 2) + '\n\nПроведи детальную оценку соответствия кандидата вакансии по критериям:\n1. Должность / роль (0-30 баллов)\n2. Навыки (0-35 баллов)\n3. Опыт (0-20 баллов)\n4. Город / формат / зарплата (0-15 баллов)\n\nВерни JSON с оценками и обоснованием.'
        }
      ],
      response_format: {
        type: 'json_schema',
        json_schema: {
          name: 'judge_evaluation_result',
          strict: true,
          schema: {
            type: 'object',
            additionalProperties: false,
            properties: {
              vacancy_id: { type: ['string', 'null'] },
              title: { type: ['string', 'null'] },
              role_score: { type: 'number' },
              skills_score: { type: 'number' },
              experience_score: { type: 'number' },
              conditions_score: { type: 'number' },
              score: { type: 'number' },
              decision: {
                type: 'string',
                enum: ['match', 'no_match']
              },
              reason: { type: 'string' }
            },
            required: ['vacancy_id', 'title', 'role_score', 'skills_score', 
                       'experience_score', 'conditions_score', 'score', 
                       'decision', 'reason']
          }
        }
      }
    }
  }
}];

function extractRaw(itemJson) {
  return itemJson.choices?.[0]?.message?.content || '';
}

function parseJson(raw, fallback) {
  if (!raw || typeof raw !== 'string') {
    return fallback;
  }

  let cleaned = raw.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return fallback;

    try {
      return JSON.parse(match[0]);
    } catch (e2) {
      return fallback;
    }
  }
}

// Get latency from explicit timestamp
const requestStartedAt = Number($('Prepare Judge Request').first().json.request_started_at);
const latencyMs = Number.isFinite(requestStartedAt) && requestStartedAt > 0
  ? Date.now() - requestStartedAt
  : 0;

const raw = extractRaw($json);
const parsed = parseJson(raw, {
  vacancy_id: null,
  title: '',
  role_score: 0,
  skills_score: 0,
  experience_score: 0,
  conditions_score: 0,
  score: 0,
  decision: 'no_match',
  reason: 'Failed to parse response'
});

const caseVacancyId = $('Prepare Judge Request').first().json.case_vacancy_id;

return [{
  json: {
    case_vacancy_id: caseVacancyId,
    reference_score: parsed.score,
    reference_decision: parsed.decision,
    reference_reason: parsed.reason,
    raw_response: raw,
    latency_ms: latencyMs,
    parsed: parsed
  }
}];

// Return to Split In Batches for next iteration
return [{
  json: {
    continue: true
  }
}];

