const metrics = $json;
const config = $('Run Config').first().json;
const experimentData = $('PG: Check Experiment').first().json;

const maeImprovement = parseFloat(metrics.mae_improvement) || 0;
const latencyGrowth = parseFloat(metrics.latency_growth) || 0;

const maeThreshold = 0.20; // 20%
const latencyThreshold = 0.30; // 30%

const maePassed = maeImprovement >= maeThreshold;
const latencyPassed = latencyGrowth <= latencyThreshold;

const finalDecision = maePassed && latencyPassed ? 'ACCEPT PROMPT B' : 'REJECT PROMPT B';

const reason = [];
if (!maePassed) {
  reason.push(`MAE improvement ${maeImprovement.toFixed(2)} is below threshold ${maeThreshold}`);
}
if (!latencyPassed) {
  reason.push(`Latency growth ${latencyGrowth.toFixed(2)} exceeds threshold ${latencyThreshold}`);
}

return [{
  json: {
    experiment_code: config.experiment_code,
    dataset_code: config.dataset_code,
